begin;

-- 1. 算命学 十大主星
insert into public.sanmei_stars (code, name, type_name, short_description, long_description, sort_order, is_active) values
  ('kansaku', '貫索星', '守りの自立者', '自分の軸を守り、時間をかけて信頼を積み上げる星です。周囲に流されすぎず、決めたことを守り抜く力があります。', '貫索星は、自立心・継続力・守る力を象徴します。急な変化や過度な干渉よりも、自分のペースで積み上げる環境で力を発揮します。頑固に見られることもありますが、裏を返せば簡単にはぶれない芯の強さです。', 1, true),
  ('sekimon', '石門星', 'つながりの調整者', '人との縁を広げ、仲間や組織の中で力を発揮する星です。調整力と協調性が魅力になります。', '石門星は、協調・仲間・横のつながりを象徴します。ひとりで完結するより、同じ目的を持つ人たちと関わることで運が動きやすくなります。人に合わせる力がある一方で、流されすぎると自分の本音を見失いやすい点には注意が必要です。', 2, true),
  ('houkaku', '鳳閣星', '表現する太陽', '自然体の表現力と明るさを持つ星です。無理に飾らず、楽しむことが魅力につながります。', '鳳閣星は、伝える力・遊び心・自然な表現を象徴します。人を緊張させず、場を和ませる才能があります。成果を急ぎすぎるより、好きなことを続けながら表に出していくことで評価されやすい星です。', 3, true),
  ('chousho', '調舒星', '感性の表現者', '繊細な感受性と独自の表現を持つ星です。人と違う視点や美意識が才能になります。', '調舒星は、感性・孤独・鋭い表現力を象徴します。人の気持ちや場の空気を深く受け取り、自分だけの言葉や作品に変える力があります。傷つきやすさもありますが、その繊細さこそが洞察や創作の源になります。', 4, true),
  ('rokuzon', '禄存星', '現実を動かす人', '人やお金、場を動かす引力を持つ星です。面倒見の良さと現実感覚が強みです。', '禄存星は、愛情・引力・現実的な豊かさを象徴します。人を惹きつけ、場に必要なものを集める力があります。世話を焼きすぎると疲れますが、相手のために動く力が仕事や人間関係の成果につながりやすい星です。', 5, true),
  ('shiroku', '司禄星', '信頼を積む人', '堅実さと蓄積の力を持つ星です。小さな積み重ねを大切にし、安定した信頼を築きます。', '司禄星は、蓄積・家庭性・管理力を象徴します。一気に変えるより、日々の積み重ねによって大きな成果を作るタイプです。細かい配慮や計画性が強みで、長く続く関係や仕組みを育てるほど魅力が増します。', 6, true),
  ('shaki', '車騎星', '勝負する開拓者', '行動力と突破力を持つ星です。考えすぎるより、動きながら道を切り開くことで力が出ます。', '車騎星は、行動・競争・スピードを象徴します。目標が明確になるほど集中力が高まり、困難な場面でも前に進む力があります。急ぎすぎると周囲を置いていくことがありますが、現場で動く強さは大きな武器です。', 7, true),
  ('kengyu', '牽牛星', '美意識の実力者', '責任感と品格を大切にする星です。役割を果たし、周囲から信頼されることで力を発揮します。', '牽牛星は、責任・名誉・整った美意識を象徴します。期待に応えようとする意識が強く、きちんとした場や評価基準のある環境で実力を発揮します。完璧を求めすぎると苦しくなりますが、品のある努力が評価につながる星です。', 8, true),
  ('ryuko', '龍高星', '変化を求める探究者', '未知の世界に触れ、経験から学ぶ星です。変化・移動・探究が運を動かします。', '龍高星は、探究・変化・自由な学びを象徴します。決められた枠だけに収まるより、新しい環境や知識に触れることで本質が目覚めます。安定だけを求めると退屈しやすい一方、変化を経験に変える力があります。', 9, true),
  ('gyokudo', '玉堂星', '知性の継承者', '学び、理解し、伝える力を持つ星です。知識や伝統を深めることで信頼を得ます。', '玉堂星は、知性・学習・保護を象徴します。物事をすぐに判断するより、背景や原理を理解してから動くタイプです。学んだことを体系化し、人にわかりやすく伝える力があり、教育・研究・専門性と相性が良い星です。', 10, true)
on conflict (code) do update set name=excluded.name, type_name=excluded.type_name, short_description=excluded.short_description, long_description=excluded.long_description, sort_order=excluded.sort_order, is_active=excluded.is_active, updated_at=now();

-- 2. 陽占5位置
insert into public.sanmei_positions (code, name, user_facing_label, result_section_key, description, sort_order, is_active) values
  ('head', '頭の星', 'ものごとの捉え方', 'values', '価値観、判断基準、目上や社会から受け取る考え方を表します。結果ページでは、何を重視して世界を見るかとして文章化します。', 1, true),
  ('chest', '胸の星', 'あなたの中心にある性質', 'essence', 'その人の中心にある本質や自然に出やすい性格を表します。MVPでは、この星をメインの宿命タイプとして扱います。', 2, true),
  ('left_hand', '左手の星', '仕事で力を発揮する場面', 'work', '社会、仕事、外の世界で見せる振る舞いや評価されやすい力を表します。結果ページでは働き方や活躍の場として扱います。', 3, true),
  ('right_hand', '右手の星', '親しい人との関わり方', 'relationship', '家庭、恋愛、身近な関係で出やすい態度を表します。結果ページでは親しい人への接し方として文章化します。', 4, true),
  ('stomach', '腹の星', '人生が進むほど大切になること', 'longterm', '内側の欲求、晩年のテーマ、長期的に満たされる方向を表します。結果ページでは人生後半に強まる価値観として扱います。', 5, true)
on conflict (code) do update set name=excluded.name, user_facing_label=excluded.user_facing_label, result_section_key=excluded.result_section_key, description=excluded.description, sort_order=excluded.sort_order, is_active=excluded.is_active, updated_at=now();

-- 3. 十大主星 × 陽占5位置 文章マスタ
insert into public.star_position_texts (star_id, position_id, title, free_text, premium_text, advice_text, version, is_active)
select st.id, ps.id, v.title, v.free_text, v.premium_text, v.advice_text, 1, true
from (values
  ('kansaku', 'head', '自分の軸を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「自分の軸」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '貫索星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。守りの自立者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('kansaku', 'chest', '守りの自立者として生きる人', 'あなたの中心には、自分の軸を守り、時間をかけて信頼を積み上げる星です。周囲に流されすぎず、決めたことを守り抜く力があります。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、守る力が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '貫索星が胸にある場合、人生の中心テーマは「自分の軸」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、自分の軸を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('kansaku', 'left_hand', '仕事では守る力が評価につながる', '仕事や社会的な場面では、あなたの中にある「守る力」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '貫索星が社会の場所にある人は、外の世界で守りの自立者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で守る力や継続を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の守る力を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('kansaku', 'right_hand', '親しい人には継続で関わる', '恋愛や家族、近い距離の人間関係では、「継続」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '貫索星が身近な関係の場所にある場合、親しい人との関わり方に守りの自立者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('kansaku', 'stomach', '人生後半ほど自分の軸が大切になる', '長い目で見ると、あなたは「自分の軸」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '貫索星が内側の欲求の場所にある人は、年齢を重ねるほど守りの自立者としてのテーマが強まります。表面的な成功だけでなく、日々の中で自分の軸や継続を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('sekimon', 'head', '仲間とのつながりを通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「仲間とのつながり」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '石門星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。つながりの調整者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('sekimon', 'chest', 'つながりの調整者として生きる人', 'あなたの中心には、人との縁を広げ、仲間や組織の中で力を発揮する星です。調整力と協調性が魅力になります。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、調整力が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '石門星が胸にある場合、人生の中心テーマは「仲間とのつながり」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、仲間とのつながりを隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('sekimon', 'left_hand', '仕事では調整力が評価につながる', '仕事や社会的な場面では、あなたの中にある「調整力」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '石門星が社会の場所にある人は、外の世界でつながりの調整者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で調整力や協調を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の調整力を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('sekimon', 'right_hand', '親しい人には協調で関わる', '恋愛や家族、近い距離の人間関係では、「協調」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '石門星が身近な関係の場所にある場合、親しい人との関わり方につながりの調整者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('sekimon', 'stomach', '人生後半ほど仲間とのつながりが大切になる', '長い目で見ると、あなたは「仲間とのつながり」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '石門星が内側の欲求の場所にある人は、年齢を重ねるほどつながりの調整者としてのテーマが強まります。表面的な成功だけでなく、日々の中で仲間とのつながりや協調を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('houkaku', 'head', '自然体の表現を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「自然体の表現」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '鳳閣星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。表現する太陽としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('houkaku', 'chest', '表現する太陽として生きる人', 'あなたの中心には、自然体の表現力と明るさを持つ星です。無理に飾らず、楽しむことが魅力につながります。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、楽しさが周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '鳳閣星が胸にある場合、人生の中心テーマは「自然体の表現」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、自然体の表現を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('houkaku', 'left_hand', '仕事では楽しさが評価につながる', '仕事や社会的な場面では、あなたの中にある「楽しさ」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '鳳閣星が社会の場所にある人は、外の世界で表現する太陽としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で楽しさや伝える力を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の楽しさを使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('houkaku', 'right_hand', '親しい人には伝える力で関わる', '恋愛や家族、近い距離の人間関係では、「伝える力」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '鳳閣星が身近な関係の場所にある場合、親しい人との関わり方に表現する太陽の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('houkaku', 'stomach', '人生後半ほど自然体の表現が大切になる', '長い目で見ると、あなたは「自然体の表現」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '鳳閣星が内側の欲求の場所にある人は、年齢を重ねるほど表現する太陽としてのテーマが強まります。表面的な成功だけでなく、日々の中で自然体の表現や伝える力を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('chousho', 'head', '繊細な感性を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「繊細な感性」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '調舒星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。感性の表現者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('chousho', 'chest', '感性の表現者として生きる人', 'あなたの中心には、繊細な感受性と独自の表現を持つ星です。人と違う視点や美意識が才能になります。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、独自性が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '調舒星が胸にある場合、人生の中心テーマは「繊細な感性」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、繊細な感性を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('chousho', 'left_hand', '仕事では独自性が評価につながる', '仕事や社会的な場面では、あなたの中にある「独自性」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '調舒星が社会の場所にある人は、外の世界で感性の表現者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で独自性や深い表現を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の独自性を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('chousho', 'right_hand', '親しい人には深い表現で関わる', '恋愛や家族、近い距離の人間関係では、「深い表現」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '調舒星が身近な関係の場所にある場合、親しい人との関わり方に感性の表現者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('chousho', 'stomach', '人生後半ほど繊細な感性が大切になる', '長い目で見ると、あなたは「繊細な感性」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '調舒星が内側の欲求の場所にある人は、年齢を重ねるほど感性の表現者としてのテーマが強まります。表面的な成功だけでなく、日々の中で繊細な感性や深い表現を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('rokuzon', 'head', '人を惹きつける力を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「人を惹きつける力」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '禄存星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。現実を動かす人としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('rokuzon', 'chest', '現実を動かす人として生きる人', 'あなたの中心には、人やお金、場を動かす引力を持つ星です。面倒見の良さと現実感覚が強みです。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、現実を動かす力が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '禄存星が胸にある場合、人生の中心テーマは「人を惹きつける力」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、人を惹きつける力を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('rokuzon', 'left_hand', '仕事では現実を動かす力が評価につながる', '仕事や社会的な場面では、あなたの中にある「現実を動かす力」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '禄存星が社会の場所にある人は、外の世界で現実を動かす人としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で現実を動かす力や面倒見を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の現実を動かす力を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('rokuzon', 'right_hand', '親しい人には面倒見で関わる', '恋愛や家族、近い距離の人間関係では、「面倒見」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '禄存星が身近な関係の場所にある場合、親しい人との関わり方に現実を動かす人の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('rokuzon', 'stomach', '人生後半ほど人を惹きつける力が大切になる', '長い目で見ると、あなたは「人を惹きつける力」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '禄存星が内側の欲求の場所にある人は、年齢を重ねるほど現実を動かす人としてのテーマが強まります。表面的な成功だけでなく、日々の中で人を惹きつける力や面倒見を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('shiroku', 'head', '積み重ねを通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「積み重ね」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '司禄星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。信頼を積む人としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('shiroku', 'chest', '信頼を積む人として生きる人', 'あなたの中心には、堅実さと蓄積の力を持つ星です。小さな積み重ねを大切にし、安定した信頼を築きます。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、管理力が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '司禄星が胸にある場合、人生の中心テーマは「積み重ね」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、積み重ねを隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('shiroku', 'left_hand', '仕事では管理力が評価につながる', '仕事や社会的な場面では、あなたの中にある「管理力」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '司禄星が社会の場所にある人は、外の世界で信頼を積む人としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で管理力や安心感を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の管理力を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('shiroku', 'right_hand', '親しい人には安心感で関わる', '恋愛や家族、近い距離の人間関係では、「安心感」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '司禄星が身近な関係の場所にある場合、親しい人との関わり方に信頼を積む人の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('shiroku', 'stomach', '人生後半ほど積み重ねが大切になる', '長い目で見ると、あなたは「積み重ね」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '司禄星が内側の欲求の場所にある人は、年齢を重ねるほど信頼を積む人としてのテーマが強まります。表面的な成功だけでなく、日々の中で積み重ねや安心感を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('shaki', 'head', '行動力を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「行動力」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '車騎星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。勝負する開拓者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('shaki', 'chest', '勝負する開拓者として生きる人', 'あなたの中心には、行動力と突破力を持つ星です。考えすぎるより、動きながら道を切り開くことで力が出ます。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、突破力が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '車騎星が胸にある場合、人生の中心テーマは「行動力」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、行動力を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('shaki', 'left_hand', '仕事では突破力が評価につながる', '仕事や社会的な場面では、あなたの中にある「突破力」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '車騎星が社会の場所にある人は、外の世界で勝負する開拓者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で突破力や勝負感を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の突破力を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('shaki', 'right_hand', '親しい人には勝負感で関わる', '恋愛や家族、近い距離の人間関係では、「勝負感」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '車騎星が身近な関係の場所にある場合、親しい人との関わり方に勝負する開拓者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('shaki', 'stomach', '人生後半ほど行動力が大切になる', '長い目で見ると、あなたは「行動力」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '車騎星が内側の欲求の場所にある人は、年齢を重ねるほど勝負する開拓者としてのテーマが強まります。表面的な成功だけでなく、日々の中で行動力や勝負感を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('kengyu', 'head', '責任感を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「責任感」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '牽牛星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。美意識の実力者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('kengyu', 'chest', '美意識の実力者として生きる人', 'あなたの中心には、責任感と品格を大切にする星です。役割を果たし、周囲から信頼されることで力を発揮します。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、品格が周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '牽牛星が胸にある場合、人生の中心テーマは「責任感」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、責任感を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('kengyu', 'left_hand', '仕事では品格が評価につながる', '仕事や社会的な場面では、あなたの中にある「品格」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '牽牛星が社会の場所にある人は、外の世界で美意識の実力者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で品格や評価される努力を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の品格を使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('kengyu', 'right_hand', '親しい人には評価される努力で関わる', '恋愛や家族、近い距離の人間関係では、「評価される努力」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '牽牛星が身近な関係の場所にある場合、親しい人との関わり方に美意識の実力者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('kengyu', 'stomach', '人生後半ほど責任感が大切になる', '長い目で見ると、あなたは「責任感」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '牽牛星が内側の欲求の場所にある人は、年齢を重ねるほど美意識の実力者としてのテーマが強まります。表面的な成功だけでなく、日々の中で責任感や評価される努力を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('ryuko', 'head', '変化への探究心を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「変化への探究心」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '龍高星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。変化を求める探究者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('ryuko', 'chest', '変化を求める探究者として生きる人', 'あなたの中心には、未知の世界に触れ、経験から学ぶ星です。変化・移動・探究が運を動かします。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、自由な学びが周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '龍高星が胸にある場合、人生の中心テーマは「変化への探究心」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、変化への探究心を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('ryuko', 'left_hand', '仕事では自由な学びが評価につながる', '仕事や社会的な場面では、あなたの中にある「自由な学び」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '龍高星が社会の場所にある人は、外の世界で変化を求める探究者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で自由な学びや未知への関心を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の自由な学びを使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('ryuko', 'right_hand', '親しい人には未知への関心で関わる', '恋愛や家族、近い距離の人間関係では、「未知への関心」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '龍高星が身近な関係の場所にある場合、親しい人との関わり方に変化を求める探究者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('ryuko', 'stomach', '人生後半ほど変化への探究心が大切になる', '長い目で見ると、あなたは「変化への探究心」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '龍高星が内側の欲求の場所にある人は、年齢を重ねるほど変化を求める探究者としてのテーマが強まります。表面的な成功だけでなく、日々の中で変化への探究心や未知への関心を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。'),
  ('gyokudo', 'head', '理解する力を通して世界を読む', 'あなたは物事を判断するとき、表面的な印象だけでなく「理解する力」を大切にしやすい人です。周囲の意見を聞きながらも、最終的には自分の中で納得できるかを重視します。目上の人や社会の常識に対しても、ただ従うのではなく、自分なりの意味づけができると動きやすくなります。', '玉堂星が価値観の場所にある人は、人生の選択で「何を正しいと感じるか」が大きな軸になります。知性の継承者としての性質は、情報の受け取り方や学び方に表れます。無理に周囲と同じ判断をするより、自分が大切にしたい基準を言語化すると迷いが減ります。', '大きな判断をするときは、損得だけでなく「自分の軸に合っているか」を一度書き出すと選びやすくなります。'),
  ('gyokudo', 'chest', '知性の継承者として生きる人', 'あなたの中心には、学び、理解し、伝える力を持つ星です。知識や伝統を深めることで信頼を得ます。 これは頑張って身につける才能というより、自然に出てしまう性質です。うまく使えているときは、学びが周囲にも伝わり、自分らしく動けます。反対に、この性質を抑え込みすぎると、理由のない窮屈さや停滞感につながりやすいでしょう。', '玉堂星が胸にある場合、人生の中心テーマは「理解する力」です。人からどう見られるか以上に、この性質を日常の選択に反映できているかが満足度を左右します。性格タイプ診断で見える思考癖と、この胸の星が重なることで、その人らしい才能の使い方が見えてきます。', '自分らしさを発揮したいときは、理解する力を隠すより、仕事や人間関係の中で小さく使える場面を増やしてみてください。'),
  ('gyokudo', 'left_hand', '仕事では学びが評価につながる', '仕事や社会的な場面では、あなたの中にある「学び」が表に出やすくなります。単に与えられた役割をこなすだけでなく、自分なりの強みを使って場に貢献しようとするタイプです。評価されるためには、努力を内側に閉じ込めず、成果や工夫として周囲に見える形にすることが大切です。', '玉堂星が社会の場所にある人は、外の世界で知性の継承者としての力を使うほど運が動きます。職種名だけで向き不向きを判断するより、その仕事の中で学びや知性を使えるかを見ると選択しやすくなります。', '仕事選びでは、給与や肩書きだけでなく「自分の学びを使える場面があるか」を確認するとミスマッチを減らせます。'),
  ('gyokudo', 'right_hand', '親しい人には知性で関わる', '恋愛や家族、近い距離の人間関係では、「知性」が出やすい傾向があります。外では見せない一面が、安心できる相手の前で表れます。相手に合わせようとしすぎるより、自分がどんな距離感で落ち着くのかを伝えることが、関係を長く続ける鍵になります。', '玉堂星が身近な関係の場所にある場合、親しい人との関わり方に知性の継承者の性質が出ます。無意識にしている愛情表現や不満の出方を理解すると、恋愛や家庭で同じすれ違いを繰り返しにくくなります。', '親しい相手には、察してもらうより「自分はこうされると安心する」と具体的に伝えると関係が整います。'),
  ('gyokudo', 'stomach', '人生後半ほど理解する力が大切になる', '長い目で見ると、あなたは「理解する力」を大切にできる生き方に惹かれていきます。若い時期は周囲の期待に合わせられても、人生が進むほど、自分の内側が本当に納得しているかが重要になります。焦って正解を決めるより、少しずつ自分に合う環境を選び直すことで満足度が上がります。', '玉堂星が内側の欲求の場所にある人は、年齢を重ねるほど知性の継承者としてのテーマが強まります。表面的な成功だけでなく、日々の中で理解する力や知性を感じられるかが、長期的な幸福感に影響します。', '将来設計では、肩書きや条件だけでなく「長く続けても心が消耗しないか」を基準に入れてください。')
) as v(star_code, position_code, title, free_text, premium_text, advice_text)
join public.sanmei_stars st on st.code = v.star_code
join public.sanmei_positions ps on ps.code = v.position_code
on conflict (star_id, position_id, version) do update set title=excluded.title, free_text=excluded.free_text, premium_text=excluded.premium_text, advice_text=excluded.advice_text, is_active=excluded.is_active, updated_at=now();

-- 4. 16性格タイプ
insert into public.personality_types (code, display_name, short_description, long_description, energy_axis, perception_axis, decision_axis, lifestyle_axis, sort_order, is_active) values
  ('ISTJ', '静かに責任を果たす実務家', '落ち着いて現実を見つめ、決めたことを着実に進めるタイプです。秩序や約束を大切にし、信頼される役割で力を発揮します。', '落ち着いて現実を見つめ、決めたことを着実に進めるタイプです。秩序や約束を大切にし、信頼される役割で力を発揮します。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'sensing', 'thinking', 'judging', 1, true),
  ('ISFJ', '大切な人を支える守り手', '周囲への配慮が細やかで、身近な人や場を安定させることに力を注ぐタイプです。実務力とやさしさが両立しています。', '周囲への配慮が細やかで、身近な人や場を安定させることに力を注ぐタイプです。実務力とやさしさが両立しています。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'sensing', 'feeling', 'judging', 2, true),
  ('INFJ', '静かに理想を描く洞察者', '人や物事の奥にある意味を読み取り、理想に向かって粘り強く進むタイプです。深い共感と長期的な視点を持ちます。', '人や物事の奥にある意味を読み取り、理想に向かって粘り強く進むタイプです。深い共感と長期的な視点を持ちます。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'intuitive', 'feeling', 'judging', 3, true),
  ('INTJ', '静かに未来を設計する人', '複雑な物事を構造化し、長期的な計画として組み立てるタイプです。独自の視点と改善意識が強みになります。', '複雑な物事を構造化し、長期的な計画として組み立てるタイプです。独自の視点と改善意識が強みになります。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'intuitive', 'thinking', 'judging', 4, true),
  ('ISTP', '状況を見極める実践家', '目の前の状況を冷静に観察し、必要な手を素早く打つタイプです。理屈だけでなく、実際に試して理解する力があります。', '目の前の状況を冷静に観察し、必要な手を素早く打つタイプです。理屈だけでなく、実際に試して理解する力があります。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'sensing', 'thinking', 'perceiving', 5, true),
  ('ISFP', '感性で今を味わう表現者', '穏やかで柔軟な空気を持ち、自分の感覚や美意識を大切にするタイプです。押しつけられない自由な環境で魅力が出ます。', '穏やかで柔軟な空気を持ち、自分の感覚や美意識を大切にするタイプです。押しつけられない自由な環境で魅力が出ます。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'sensing', 'feeling', 'perceiving', 6, true),
  ('INFP', '価値観を大切にする理想家', '自分の内側にある価値観や思いを大切にし、意味のあることに力を注ぐタイプです。人の痛みにも敏感です。', '自分の内側にある価値観や思いを大切にし、意味のあることに力を注ぐタイプです。人の痛みにも敏感です。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'intuitive', 'feeling', 'perceiving', 7, true),
  ('INTP', '仕組みを探る思考家', '物事の原理や矛盾を考え抜くタイプです。自由に問いを立て、納得できるまで掘り下げることで力を発揮します。', '物事の原理や矛盾を考え抜くタイプです。自由に問いを立て、納得できるまで掘り下げることで力を発揮します。 外から多くの刺激を受けるよりも、ひとりで考える時間や静かな環境でエネルギーを回復しやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'introvert', 'intuitive', 'thinking', 'perceiving', 8, true),
  ('ESTP', '流れをつかむ行動派', '場の空気やチャンスを素早く読み、動きながら結果を出すタイプです。現実感覚と大胆さがあります。', '場の空気やチャンスを素早く読み、動きながら結果を出すタイプです。現実感覚と大胆さがあります。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'sensing', 'thinking', 'perceiving', 9, true),
  ('ESFP', '場を明るくする体験派', '人との時間やその場の楽しさを大切にし、周囲を自然に明るくするタイプです。実感を伴う経験から多くを学びます。', '人との時間やその場の楽しさを大切にし、周囲を自然に明るくするタイプです。実感を伴う経験から多くを学びます。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'sensing', 'feeling', 'perceiving', 10, true),
  ('ENFP', '可能性を広げる発想家', '新しいアイデアや人との出会いに刺激を受けるタイプです。自由な発想と人を巻き込む明るさがあります。', '新しいアイデアや人との出会いに刺激を受けるタイプです。自由な発想と人を巻き込む明るさがあります。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'intuitive', 'feeling', 'perceiving', 11, true),
  ('ENTP', '発想で突破する議論家', '固定観念に疑問を持ち、新しい見方や仕組みを試すタイプです。知的な刺激や議論の中で力が出ます。', '固定観念に疑問を持ち、新しい見方や仕組みを試すタイプです。知的な刺激や議論の中で力が出ます。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。状況に合わせて柔軟に動くことを好み、余白や選択肢を残しながら進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'intuitive', 'thinking', 'perceiving', 12, true),
  ('ESTJ', '現実を整える推進者', '目的に向けて人や物事を整理し、実行に移すタイプです。責任感が強く、仕組みやルールを活かす力があります。', '目的に向けて人や物事を整理し、実行に移すタイプです。責任感が強く、仕組みやルールを活かす力があります。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'sensing', 'thinking', 'judging', 13, true),
  ('ESFJ', '人をつなぐ世話役', '周囲の状態に気づき、人が安心して動ける場を作るタイプです。協力関係や実際的な支援を大切にします。', '周囲の状態に気づき、人が安心して動ける場を作るタイプです。協力関係や実際的な支援を大切にします。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。現実の情報や具体的な経験を重視し、実際に役立つ形で物事を捉えやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'sensing', 'feeling', 'judging', 14, true),
  ('ENFJ', '人の可能性を導く伴走者', '人の成長や関係性に強い関心を持ち、周囲を前向きに導くタイプです。共感力と働きかける力があります。', '人の成長や関係性に強い関心を持ち、周囲を前向きに導くタイプです。共感力と働きかける力があります。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では人への影響や気持ちの納得感を重視し、関係性を大切にしながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'intuitive', 'feeling', 'judging', 15, true),
  ('ENTJ', '構想を実行に変える指揮者', '大きな目標を描き、そこに向けて戦略的に物事を進めるタイプです。判断力と推進力が強みです。', '大きな目標を描き、そこに向けて戦略的に物事を進めるタイプです。判断力と推進力が強みです。 人との会話や外の出来事から刺激を受け、動きながら考えがまとまりやすい傾向があります。目の前の事実だけでなく、背景にある意味や未来の可能性に意識が向きやすい傾向があります。判断では一貫性や合理性を重視し、感情よりも筋道を確認しながら決めやすい傾向があります。先に方針や予定を決めておくと安心しやすく、計画的に物事を進める傾向があります。 これは医療的・学術的な診断ではなく、自己理解のための性格タイプ整理として扱います。', 'extrovert', 'intuitive', 'thinking', 'judging', 16, true)
